#include <Client/RustylineLineReader.h>
#include <Client/RustylineCallbacks.h>
#include <Client/ClientBaseHelpers.h>

#include <base/errnoToString.h>
#include <fmt/format.h>

#include <algorithm>
#include <cctype>
#include <cerrno>
#include <cstring>
#include <fcntl.h>
#include <sys/file.h>
#include <unistd.h>

#include "rustyline-lib.rs.h"  // generated by cxx-build

namespace DB
{

struct RustylineLineReader::Impl
{
    ::rust::Box<::DB::rustyline::Editor> editor;
};

namespace
{
    void rightTrim(String & s)
    {
        s.erase(std::find_if(s.rbegin(), s.rend(),
                             [](unsigned char ch) { return !std::isspace(ch); }).base(),
                s.end());
    }
}

void RustylineLineReader::setLastIsDelimiter(bool flag)
{
    ::DB::rustyline::set_last_is_delimiter(flag);
}

RustylineLineReader::RustylineLineReader(Options && options)
    : LineReader(options.history_file_path, options.multiline,
                 std::move(options.extenders), std::move(options.delimiters),
                 options.input_stream, options.output_stream, options.in_fd)
{
    ::DB::rustyline::EditorOptions opts;
    opts.history_max_entries = options.history_max_entries;
    opts.ignore_shell_suspend = options.ignore_shell_suspend;
    opts.embedded_mode = options.embedded_mode;
    opts.interactive_history_legacy_keymap = options.interactive_history_legacy_keymap;
    opts.enable_highlight = options.enable_highlight;
    opts.multiline = options.multiline;
    opts.word_break_characters = ::rust::String(options.word_break_characters.data(),
                                                options.word_break_characters.size());

    impl = std::make_unique<Impl>(Impl{::DB::rustyline::new_editor(opts)});

    if (!history_file_path.empty())
    {
        try
        {
            /// rustyline's FileHistory takes an fd_lock RwLock internally,
            /// so we don't need our own flock() coordination.
            impl->editor->load_history(history_file_path);
        }
        catch (const std::exception & e)
        {
            fmt::print(stderr, "Loading history failed: {}\n", e.what());
        }
    }
}

RustylineLineReader::~RustylineLineReader() = default;

LineReader::InputStatus RustylineLineReader::readOneLine(const String & prompt)
{
    input.clear();
    try
    {
        auto r = impl->editor->read_line(prompt);
        switch (r.status)
        {
            case ::DB::rustyline::ReadStatus::Line:
                input = std::string(r.text);
                rightTrim(input);
                return INPUT_LINE;
            case ::DB::rustyline::ReadStatus::Interrupted:
                return RESET_LINE;
            case ::DB::rustyline::ReadStatus::Eof:
                return ABORT;
            case ::DB::rustyline::ReadStatus::Error:
                fmt::print(stderr, "Line reader error: {}\n", std::string(r.text));
                return ABORT;
        }
    }
    catch (const std::exception & e)
    {
        fmt::print(stderr, "Line reader exception: {}\n", e.what());
        return ABORT;
    }
}

void RustylineLineReader::addToHistory(const String & line)
{
    try
    {
        impl->editor->add_history(line);
        if (!history_file_path.empty())
            impl->editor->save_history(history_file_path);
    }
    catch (const std::exception & e)
    {
        fmt::print(stderr, "Saving history failed: {}\n", e.what());
    }
}

void RustylineLineReader::enableBracketedPaste()
{
    bracketed_paste_enabled = true;
    impl->editor->enable_bracketed_paste(true);
}

void RustylineLineReader::disableBracketedPaste()
{
    bracketed_paste_enabled = false;
    impl->editor->enable_bracketed_paste(false);
}

void RustylineLineReader::setInitialText(const String & text)
{
    impl->editor->set_preload(text);
}

}
